import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { searchRentals, fetchStates, fetchPropertyTypes } from '../utils/api';
import { LoadingState, ErrorState, EmptyState } from '../components/LoadingState';
import Pagination from '../components/Pagination';

const SORT_COLUMNS = [
  { value: 'rent', label: 'Price' },
  { value: 'bedrooms', label: 'Bedrooms' },
  { value: 'bathrooms', label: 'Bathrooms' },
  { value: 'parkingSpaces', label: 'Parking' },
  { value: 'suburb', label: 'Suburb' },
];

const formatPrice = (p) =>
  p != null ? `$${Number(p).toLocaleString('en-AU')}/wk` : '—';

const SearchPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [states, setStates] = useState([]);
  const [propertyTypes, setPropertyTypes] = useState([]);

  const [filters, setFilters] = useState({
    state: searchParams.get('state') || '',
    suburb: searchParams.get('suburb') || '',
    postcode: searchParams.get('postcode') || '',
    propertyType: searchParams.get('propertyType') || '',
    minRent: searchParams.get('minRent') || '',
    maxRent: searchParams.get('maxRent') || '',
    bedrooms: searchParams.get('bedrooms') || '',
    bathrooms: searchParams.get('bathrooms') || '',
    parkingSpaces: searchParams.get('parkingSpaces') || '',
    sortBy: searchParams.get('sortBy') || '',
    sortOrder: searchParams.get('sortOrder') || 'asc',
  });

  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(Number(searchParams.get('page')) || 1);
  const [showAdvanced, setShowAdvanced] = useState(false);

  const debounceRef = useRef(null);

  useEffect(() => {
    fetchStates().then(setStates).catch(() => {});
    fetchPropertyTypes().then(setPropertyTypes).catch(() => {});
  }, []);

  const doSearch = useCallback(async (currentFilters, currentPage) => {
    setLoading(true);
    setError(null);

    try {
      const params = {
        ...currentFilters,
        page: currentPage,
      };

      Object.keys(params).forEach((k) => {
        if (params[k] === '' || params[k] == null) {
          delete params[k];
        }
      });

      const data = await searchRentals(params);
      setResults(data);

    } catch (err) {
      setError(err.message || 'Search failed. Please try again.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
    }

    debounceRef.current = setTimeout(() => {
      doSearch(filters, page);

      const params = {};

      Object.entries(filters).forEach(([k, v]) => {
        if (v) {
          params[k] = v;
        }
      });

      if (page > 1) {
        params.page = page;
      }

      setSearchParams(params, { replace: true });

    }, 400);

    return () => clearTimeout(debounceRef.current);

  }, [filters, page, doSearch, setSearchParams]);

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({
      ...prev,
      [key]: value,
    }));
    setPage(1);
  };

  const handleSortCol = (col) => {
    setFilters((prev) => ({
      ...prev,
      sortBy: col,
      sortOrder:
        prev.sortBy === col && prev.sortOrder === 'asc'
          ? 'desc'
          : 'asc',
    }));

    setPage(1);
  };

  const resetFilters = () => {
    setFilters({
      state: '',
      suburb: '',
      postcode: '',
      propertyType: '',
      minRent: '',
      maxRent: '',
      bedrooms: '',
      bathrooms: '',
      parkingSpaces: '',
      sortBy: '',
      sortOrder: 'asc',
    });

    setPage(1);
  };

  const rentals = results?.data || [];
  const totalPages = results?.pagination?.lastPage || 1;

  return (
    <div className="search-page">
      <div className="search-page__sidebar">
        <div className="filter-panel">

          <div className="filter-panel__header">
            <h2>Filters</h2>
            <button className="btn btn--link" onClick={resetFilters}>
              Reset
            </button>
          </div>

          <div className="filter-group">
            <label className="filter-label">State</label>
            <select
              className="filter-select"
              value={filters.state}
              onChange={(e) =>
                handleFilterChange('state', e.target.value)
              }
            >
              <option value="">All States</option>
              {states.map((s) => (
                <option key={s} value={s}>
                  {s}
                </option>
              ))}
            </select>
          </div>

          <div className="filter-group">
            <label className="filter-label">Property Type</label>
            <select
              className="filter-select"
              value={filters.propertyType}
              onChange={(e) =>
                handleFilterChange('propertyType', e.target.value)
              }
            >
              <option value="">All Types</option>
              {propertyTypes.map((t) => (
                <option key={t} value={t}>
                  {t}
                </option>
              ))}
            </select>
          </div>

          <div className="filter-group">
            <label className="filter-label">Suburb</label>
            <input
              className="filter-input"
              value={filters.suburb}
              onChange={(e) =>
                handleFilterChange('suburb', e.target.value)
              }
            />
          </div>

          <div className="filter-group">
            <label className="filter-label">Postcode</label>
            <input
              className="filter-input"
              value={filters.postcode}
              onChange={(e) =>
                handleFilterChange('postcode', e.target.value)
              }
            />
          </div>

          <button
            className="btn btn--link filter-advanced-toggle"
            onClick={() =>
              setShowAdvanced(!showAdvanced)
            }
          >
            {showAdvanced
              ? '− Hide Advanced'
              : '+ Advanced Filters'}
          </button>

          {showAdvanced && (
            <>
              <div className="filter-group">
                <input
                  className="filter-input"
                  placeholder="Min Rent"
                  value={filters.minRent}
                  onChange={(e) =>
                    handleFilterChange('minRent', e.target.value)
                  }
                />
              </div>

              <div className="filter-group">
                <input
                  className="filter-input"
                  placeholder="Max Rent"
                  value={filters.maxRent}
                  onChange={(e) =>
                    handleFilterChange('maxRent', e.target.value)
                  }
                />
              </div>

              <div className="filter-group">
                <input
                  className="filter-input"
                  placeholder="Bedrooms"
                  value={filters.bedrooms}
                  onChange={(e) =>
                    handleFilterChange('bedrooms', e.target.value)
                  }
                />
              </div>

              <div className="filter-group">
                <input
                  className="filter-input"
                  placeholder="Bathrooms"
                  value={filters.bathrooms}
                  onChange={(e) =>
                    handleFilterChange('bathrooms', e.target.value)
                  }
                />
              </div>

              <div className="filter-group">
                <input
                  className="filter-input"
                  placeholder="Parking"
                  value={filters.parkingSpaces}
                  onChange={(e) =>
                    handleFilterChange(
                      'parkingSpaces',
                      e.target.value
                    )
                  }
                />
              </div>
            </>
          )}

        </div>
      </div>

      <div className="search-page__results">
        <h1>
          {loading
            ? 'Searching…'
            : `${rentals.length} results`}
        </h1>

        {loading && <LoadingState />}
        {error && <ErrorState message={error} />}
        {!loading && rentals.length === 0 && (
          <EmptyState title="No properties found" />
        )}

        {!loading && rentals.length > 0 && (
          <>
            <table className="results-table">
              <tbody>
                {rentals.map((r) => (
                  <tr
                    key={r.id}
                    onClick={() =>
                      navigate(`/rental/${r.id}`)
                    }
                  >
                    <td>{r.suburb}</td>
                    <td>{r.state}</td>
                    <td>{r.propertyType}</td>
                    <td>{formatPrice(r.rent)}</td>
                  </tr>
                ))}
              </tbody>
            </table>

            <Pagination
              page={page}
              totalPages={totalPages}
              onPageChange={setPage}
            />
          </>
        )}
      </div>
    </div>
  );
};

export default SearchPage;
